import { Hono } from 'hono';
import { z } from 'zod';

const app = new Hono();

const AssignTaskSchema = z.object({
  assigneeId: z.string(),
});

app.put('/tasks/:taskId/assign', async (c) => {
  const taskId = c.req.param('taskId');
  const body = await c.req.json();
  const parsedBody = AssignTaskSchema.safeParse(body);

  if (!parsedBody.success) {
    return c.json({ error: 'Invalid request body' }, 400);
  }

  const { assigneeId } = parsedBody.data;

  // Assuming you have a function to check if the assignee is in the task's team
  const isAssigneeInTeam = await checkIfAssigneeIsInTaskTeam(taskId, assigneeId);

  if (!isAssigneeInTeam) {
    return c.json({ error: 'Assignee is not a member of the task\'s team' }, 403);
  }

  // Assuming you have a function to update the task assignment
  await updateTaskAssignment(taskId, assigneeId);

  return c.json({ message: 'Task assigned successfully' });
});

